import React, { useState, useEffect } from "react";
import axios from "axios";
import { FaKey } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import styles from "./verifyotp.module.css"; // ✅ Import as a module

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [otpError, setOtpError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();
  const userEmail = localStorage.getItem("resetEmail");

  useEffect(() => {
    if (!userEmail) {
      navigate("/forgot-password");
    }
  }, [userEmail, navigate]);

  const handleOtpVerification = async (e) => {
    e.preventDefault();
    setOtpMessage("");
    setOtpError("");

    if (!otp.trim()) {
      setOtpError("OTP is required.");
      return;
    }

    try {
      setIsSubmitting(true);
      console.log("Verifying OTP...");

      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", {
        email: userEmail,
        otp,
      });

      console.log("Response:", response.data);

      if (response.data?.success) {
        setOtpMessage(response.data.message || "OTP verified successfully!");
        localStorage.setItem("otpVerified", "true");
        setTimeout(() => navigate("/reset-password"), 1000);
      } else {
        setOtpError(response.data.message || "Invalid OTP.");
      }
    } catch (err) {
      setOtpError("Error verifying OTP. Please try again.");
      console.error("Verify OTP Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className={styles.verifyOtpContainer}>
      <img src="/assets/ODCSE Logo.png" alt="Logo" className={styles.logo} />

      <form onSubmit={handleOtpVerification} className={styles.verifyOtpForm}>
        <h2>Verify OTP</h2>
        <p>Enter the OTP sent to your registered email</p>

        <div className={styles.inputGroup}>
          <FaKey className={styles.icon} />
          <input
            type="text"
            placeholder="Enter OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            required
            disabled={isSubmitting}
          />
        </div>

        <button type="submit" className={styles.verifyOtpButton} disabled={isSubmitting}>
          {isSubmitting ? "Verifying..." : "Verify OTP"}
        </button>

        <div>
          {otpMessage && <p className={styles.successMessage}>{otpMessage}</p>}
          {otpError && <p className={styles.errorMessage}>{otpError}</p>}
        </div>
      </form>

      <div>
        <button onClick={() => navigate("/forgot-password")} className={styles.backButton}>
          Back
        </button>
      </div>
    </div>
  );
};

export default VerifyOtpPage;
